@startuml
skinparam classDiagram
    class AnimalVision {
        +grass : double[]
        +hares : double[]
        +wolfes : double[]
        +land : double[]
        +water : double[]
        +AnimalVision()
        +getJoined()
    }

    class DoubleToGrayCode {
        +minValue : int
        +maxValue : int
        +size : int
        +bits : int
        +pieces : int
        +doubleToGC()
        +gCToDouble()
    }

    class Brain {
        +Brain()
        +Brain()
        +breed()
        +makeDecision()
    }

    class VisionFactory {
        +animalSight : int
        +VisionFactory()
        +seeBlocks()
        +seeGrass()
        +seeAnimals()
        +getPoint()
    }

    class NeuralNetwork {
        +inputLayer : double[][]
        +innerLayers : double[][][]
        +outputLayer : double[][]
        +inputSize : int
        +innerSize : int
        +outputSize : int
        +NeuralNetwork()
        +NeuralNetwork()
        +genotype()
        +calculate()
        +activationF()
    }

    class Genotype {
        +genes : int[]
        +Genotype()
        +getGenes()
        +breed()
        +crossover()
        +arrayExchange()
        +bitExchange()
        +mutation()
    }

    class Coordinate {
    }

    class WorldMap {
    }

    class AnimalManager {
    }

    class AI {
        +AnimalVision
        +DoubleToGrayCode
        +Brain
        +VisionFactory
        +NeuralNetwork
    }

    class Animal {
        +AI
    }

    class Eden {
        +Animal
    }

    class Dekinci {
        +Eden
    }

    class Com {
        +Dekinci
    }

    AI ..> Brain : neuralNetwork
    AI ..> VisionFactory : manager
    AI ..> NeuralNetwork : neuralNetwork
    AI ..> Genotype : genes
    AI ..> DoubleToGrayCode : gCToDouble
    AI ..> AnimalVision : getJoined
    Animal ..> AI : ai
    Eden ..> Animal : animal
    Dekinci ..> Eden : eden
    Com ..> Dekinci : kom

@enduml
